{
  "type": "FLIP_CARD",
  "lessonText": "Understanding major and minor scales is fundamental to music theory.",
  "data": {
    "cards": [
      {
        "front": "What is a Major Scale?",
        "back": "A major scale is a seven-note scale that follows the pattern: whole, whole, half, whole, whole, whole, half.",
        "icon": "🎶"
      },
      {
        "front": "What is a Minor Scale?",
        "back": "A minor scale is a seven-note scale that follows the pattern: whole, half, whole, whole, half, whole, whole.",
        "icon": "🎵"
      },
      {
        "front": "Difference between Major and Minor Scales?",
        "back": "Major scales sound happy and bright, while minor scales sound sad and dark.",
        "icon": "⚖️"
      },
      {
        "front": "Example of C Major Scale?",
        "back": "C, D, E, F, G, A, B, C.",
        "icon": "🔤"
      }
    ]
  }
}
